// WooCommerce signs every webhook: HMAC-SHA256 over the raw body,
// using our shared secret, sent in the x-wc-webhook-signature header.
// We recompute it and compare — matching proof the call is really our shop.
const crypto = require('crypto');

const secret = $env.WC_WEBHOOK_SECRET;
if (!secret) throw new Error('WC_WEBHOOK_SECRET not set in n8n environment');

const headers = $input.first().json.headers;
const signature = headers['x-wc-webhook-signature'];

// Recover the exact raw bytes WooCommerce sent (Raw Body option)
const rawBinary = $input.first().binary?.data;
if (!rawBinary) throw new Error('Raw body missing — enable Raw Body on the Webhook node');
const rawBody = Buffer.from(rawBinary.data, 'base64').toString('utf8');

// WooCommerce sends a plain "ping" when a webhook is first saved — not an order.
// Acknowledge it quietly and stop.
if (rawBody.startsWith('webhook_id=')) {
  return [];
}

if (!signature) throw new Error('Missing signature header — request rejected');

// Recompute the HMAC and compare in constant time (prevents timing attacks)
const expected = crypto.createHmac('sha256', secret).update(rawBody, 'utf8').digest('base64');
const a = Buffer.from(signature);
const b = Buffer.from(expected);
if (a.length !== b.length || !crypto.timingSafeEqual(a, b)) {
  throw new Error('Invalid webhook signature — request rejected');
}

// Signature valid — parse the order and pass it downstream
const order = JSON.parse(rawBody);
return [{ json: order }];

const helpers = this.helpers;
const url = $env.TWENTY_API_URL;
const key = $env.TWENTY_API_KEY;

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: url + '/graphql',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { query, variables },
    json: true,
  });
  if (res.errors) throw new Error('Twenty GraphQL error: ' + JSON.stringify(res.errors));
  return res.data;
}

const order = $json;
const email = ((order.billing && order.billing.email) || '').trim().toLowerCase();
const firstName = (order.billing && order.billing.first_name) || '';
const lastName = (order.billing && order.billing.last_name) || '';

if (!email) {
  throw new Error('Order #' + order.number + ' has no billing email - cannot upsert Person');
}

const findQuery = `query FindPerson($email: String!) {
  people(filter: { emails: { primaryEmail: { eq: $email } } }, first: 1) {
    edges { node { id } }
  }
}`;

const findResult = await gql(findQuery, { email });
const existing = findResult.people.edges[0];

let personId;
if (existing) {
  personId = existing.node.id;
} else {
  const createMutation = `mutation CreatePerson($data: PersonCreateInput!) {
    createPerson(data: $data) { id }
  }`;
  const createResult = await gql(createMutation, {
    data: {
      name: { firstName, lastName },
      emails: { primaryEmail: email },
    },
  });
  personId = createResult.createPerson.id;
}

return [{ json: { ...order, _personId: personId, _personEmail: email } }];

const helpers = this.helpers;
const url = $env.TWENTY_API_URL;
const key = $env.TWENTY_API_KEY;

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: url + '/graphql',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { query, variables },
    json: true,
  });
  if (res.errors) throw new Error('Twenty GraphQL error: ' + JSON.stringify(res.errors));
  return res.data;
}

const order = $json;
const lineItems = order.line_items || [];
const currencyCode = (order.currency || 'USD').toUpperCase();

// De-dupe by SKU within this order (defensive - Woo shouldn't repeat a SKU
// as two separate line items, but don't do redundant API calls if it does).
const bySku = new Map();
for (const li of lineItems) {
  if (!li.sku) continue; // no SKU on this line - Upsert Products can't key it; Create Line Items will fail loudly later if it's actually needed
  if (!bySku.has(li.sku)) bySku.set(li.sku, li);
}

const productMap = {};

for (const [sku, li] of bySku.entries()) {
  const unitPrice = Number(li.price) || 0;
  const amountMicros = Math.round(unitPrice * 1000000);

  const findQuery = `query FindProduct($sku: String!) {
    products(filter: { sku: { eq: $sku } }, first: 1) {
      edges { node { id } }
    }
  }`;
  const findResult = await gql(findQuery, { sku });
  const existing = findResult.products.edges[0];

  let productId;
  if (existing) {
    productId = existing.node.id;
    // Product is a LIVE record (not a snapshot) - keep its Current Price fresh.
    // The historical price-as-sold is preserved separately on the Order Line
    // Item created downstream, so updating this never rewrites history.
    const updateMutation = `mutation UpdateProduct($id: UUID!, $data: ProductUpdateInput!) {
      updateProduct(id: $id, data: $data) { id }
    }`;
    await gql(updateMutation, {
      id: productId,
      data: { currentPrice: { amountMicros, currencyCode } },
    });
  } else {
    const createMutation = `mutation CreateProduct($data: ProductCreateInput!) {
      createProduct(data: $data) { id }
    }`;
    const createResult = await gql(createMutation, {
      data: {
        sku,
        name: li.name,
        currentPrice: { amountMicros, currencyCode },
      },
    });
    productId = createResult.createProduct.id;
  }

  productMap[sku] = productId;
}

return [{ json: { ...order, _productMap: productMap } }];

const helpers = this.helpers;
const url = $env.TWENTY_API_URL;
const key = $env.TWENTY_API_KEY;

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: url + '/graphql',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { query, variables },
    json: true,
  });
  if (res.errors) throw new Error('Twenty GraphQL error: ' + JSON.stringify(res.errors));
  return res.data;
}

const order = $json;
const wooOrderNumber = String(order.number || order.id);
const currencyCode = (order.currency || 'USD').toUpperCase();
const totalAmountMicros = Math.round((Number(order.total) || 0) * 1000000);
const orderDate = ((order.date_created || order.date_created_gmt || '').split('T')[0]) || null;

const findQuery = `query FindOrder($n: String!) {
  orders(filter: { wooOrderNumber: { eq: $n } }, first: 1) {
    edges { node { id syncStatus } }
  }
}`;
const findResult = await gql(findQuery, { n: wooOrderNumber });
const existing = findResult.orders.edges[0];

let orderId;
let alreadySynced = false;
let isNewOrder = false;

if (existing) {
  orderId = existing.node.id;
  alreadySynced = existing.node.syncStatus === 'STATUS_SYNCED';
} else {
  const createMutation = `mutation CreateOrder($data: OrderCreateInput!) {
    createOrder(data: $data) { id syncStatus }
  }`;
  const createResult = await gql(createMutation, {
    data: {
      wooOrderNumber,
      total: { amountMicros: totalAmountMicros, currencyCode },
      orderDate,
      syncStatus: 'STATUS_PENDING',
      customerId: order._personId,
    },
  });
  orderId = createResult.createOrder.id;
  isNewOrder = true;
  alreadySynced = false;
}

return [{ json: { ...order, _orderId: orderId, _alreadySynced: alreadySynced, _isNewOrder: isNewOrder } }];

const helpers = this.helpers;
const url = $env.TWENTY_API_URL;
const key = $env.TWENTY_API_KEY;

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: url + '/graphql',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { query, variables },
    json: true,
  });
  if (res.errors) throw new Error('Twenty GraphQL error: ' + JSON.stringify(res.errors));
  return res.data;
}

const order = $json;
const orderId = order._orderId;
const productMap = order._productMap || {};
const lineItems = order.line_items || [];
const currencyCode = (order.currency || 'USD').toUpperCase();

const created = [];
const skipped = [];

for (const li of lineItems) {
  if (!li.sku) {
    throw new Error('Line item "' + li.name + '" on order ' + order.number + ' has no SKU - cannot link to a Product');
  }
  const productId = productMap[li.sku];
  if (!productId) {
    throw new Error('No Twenty product id found for SKU ' + li.sku + ' on order ' + order.number + ' - Upsert Products must run before this node');
  }

  // Woo variation attributes (e.g. Plan: Signature) come through as meta_data
  // with display_key/display_value. Join all display_values - our catalog only
  // ever has one (Plan), but this doesn't assume that.
  const variation = ((li.meta_data || [])
    .map((m) => m.display_value)
    .filter(Boolean)
    .join(', ')) || null;

  const unitPriceMicros = Math.round((Number(li.price) || 0) * 1000000);
  const lineTotalMicros = Math.round((Number(li.total) || 0) * 1000000);

  // Idempotency guard at line-item granularity: if a line item for this exact
  // order + product (+ variation) already exists, skip it. This is what makes
  // retry-after-partial-failure safe even if a previous run of this node
  // crashed after creating only some of the order's line items - and it's a
  // second, finer-grained safety net under the order-level Sync Status guard
  // (which already skips this whole node when the order was fully synced).
  const variationFilter = variation ? { eq: variation } : { is: 'NULL' };
  const findQuery = `query FindLineItem($orderId: UUID!, $productId: UUID!, $variationFilter: StringFilter) {
    orderLineItems(filter: { order: { id: { eq: $orderId } }, product: { id: { eq: $productId } }, variation: $variationFilter }, first: 1) {
      edges { node { id } }
    }
  }`;
  const findResult = await gql(findQuery, { orderId, productId, variationFilter });
  if (findResult.orderLineItems.edges.length > 0) {
    skipped.push({ sku: li.sku, id: findResult.orderLineItems.edges[0].node.id });
    continue;
  }

  const createMutation = `mutation CreateLineItem($data: OrderLineItemCreateInput!) {
    createOrderLineItem(data: $data) { id }
  }`;
  const createResult = await gql(createMutation, {
    data: {
      name: li.name, // snapshot of the product name AS SOLD - not a live lookup
      quantity: li.quantity,
      unitPrice: { amountMicros: unitPriceMicros, currencyCode },
      lineTotal: { amountMicros: lineTotalMicros, currencyCode },
      variation,
      orderId,
      productId,
    },
  });
  created.push({ sku: li.sku, id: createResult.createOrderLineItem.id });
}

return [{ json: { ...order, _lineItemsCreated: created, _lineItemsSkipped: skipped } }];

const helpers = this.helpers;
const url = $env.TWENTY_API_URL;
const key = $env.TWENTY_API_KEY;

async function gql(query, variables) {
  const res = await helpers.httpRequest({
    method: 'POST',
    url: url + '/graphql',
    headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
    body: { query, variables },
    json: true,
  });
  if (res.errors) throw new Error('Twenty GraphQL error: ' + JSON.stringify(res.errors));
  return res.data;
}

const order = $json;

// Deliberately the LAST step of the whole chain: an idempotent resume marker.
// If everything above already ran to completion for this order, this is the
// only thing left to do; if the workflow crashes before this point and is
// retried, steps 1-4 are all safe upserts / existence checks, so re-running
// them causes no duplicates, and this flip only ever happens once real work
// is actually done.
const mutation = `mutation SetSynced($id: UUID!, $data: OrderUpdateInput!) {
  updateOrder(id: $id, data: $data) { id syncStatus }
}`;
const result = await gql(mutation, { id: order._orderId, data: { syncStatus: 'STATUS_SYNCED' } });

return [{ json: { ...order, _syncStatus: result.updateOrder.syncStatus } }];
